var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"본부와의 통신은 아직인가요, 리브 경?","JPN":"本部との通信はまだですか、リブ卿？","ENG":"Still no word from HQ, Dame Liv?","TWN":"還沒有和總部取得聯絡嗎，莉芙？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"응. 침식파의 영향인지 통신기가 완전 맛이 가버렸네.","JPN":"うん。侵食波の影響か、通信機が完全に壊れちゃってるみたい。","ENG":"Nope. I think the Corruption ray fried the transmitter. Totally busted.","TWN":"嗯。可能是受到侵蝕波的影響，通訊器完全壞掉了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스. 이거 네 능력으로는 못 고쳐?","JPN":"アリウスの力で修理できない？","ENG":"Arius, can't you fix it with your powers?","TWN":"埃里奧斯。這個你用你的能力修不好嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"리브 언니… 제 능력으로 기계는 못 고쳐요.","JPN":"リブさん……私の能力で機械は直せません。","ENG":"Sorry, Liv... My powers don't work on machines.","TWN":"莉芙姊姊…我的能力無法修理機械。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어, 그래? 난 왜 기계한테도 되는 줄 알았지?","JPN":"え、そうなの？　機械にも効くのかと思ってた。","ENG":"Huh, really? I thought they worked on machines too for some reason.","TWN":"喔，是嗎？我還以為對機器也有效呢？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"금방 풀어지는 건 리브 경의 나쁜 버릇입니다. 사태가 갑작스러웠으니, 저희는 어디서 나타날지 모르는 침식체를 꾸준히 경계해야 해요.","JPN":"すぐ緊張を解くのはリブ卿の悪い癖です。状況が急変した以上、どこから侵食体が現れるかわからないので警戒を怠らないことです。","ENG":"Your mood shifts far too easily, Dame Liv. With things so unpredictable, we must stay alert for any C.O.s that might appear.","TWN":"輕易放鬆警惕是莉芙的壞習慣。事態突如其來，我們必須時刻警惕那些隨時可能出現的侵蝕體。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"저희 로웰 가의 고조부께서도 말씀하셨죠. 자고로 평화와 위기는 동전의 앞 뒷면과 같고, 이를 대비하는 것이 기사단의 덕목이다. 조금 설명 드리자면 고조부님께서 오베르뉴에 계시던 시절부터 시작해야 하는데-.","JPN":"我がローウェル家の高祖父も言っていました。古くから平和と危機は表裏一体であり、それに備えることこそが騎士団の嗜みである、と。この話をするには、高祖父がオーヴェルニュにいた頃から話す必要があるのですが……。","ENG":"As my great-great-grandfather from House Lowell used to say, \\"Peace and crisis are two sides of the same coin, and preparing for both is a knight's duty.\\" Now, to explain that, we must begin from the time he served in Auvergne–","TWN":"我們勞威爾家的高祖也曾說過，所謂和平與危機就像硬幣的兩面，而做好準備是騎士團的美德。簡單來說，要從高祖在奧弗涅的時代開始講起——。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아악-! 그 놈의 고조부! 그리고 통신 좀 안 될 수도 있지 뭘 그리 들들 볶아?","JPN":"ああもう！　その高祖父の話、もういいって！　それに通信が繋がらないくらいで大騒ぎしすぎ！","ENG":"Aagh, not the great-great-grandpa speech again! So what if the comms are down? Stop harping on it!","TWN":"啊啊-！ 那個傢伙的曾祖父！ 通訊有時候不通也是正常的，為什麼要這麼煩人呢?"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경을 도우려는 건 아니지만, 해당 발언에는 저도 동의합니다, 부단장님.","JPN":"リブ卿の肩を持つつもりはありませんが、その点については私も同意見です、副団長。","ENG":"I'm not trying to side with Dame Liv, but I do agree with her this time, Deputy.","TWN":"雖然我並不是想幫莉芙，但我同意她的說法，副團長。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"갑작스러운 침식사태에 대항하기 위해 태스크포스들이 각 지부 중심으로 배치된 상황에서.","JPN":"急な侵食事態への対処で、タスクフォースが各支部を中心に配置されている現状を考えると……","ENG":"Given the sudden Corruption disaster, all TASKFORCEs have been deployed to the center of each branch.","TWN":"為了應對突如其來的侵蝕事件，各特遣勢力已在各分部中心部署。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"주요 병력이 자리를 비웠다고는 하나, 본부가 위험에 처할 확률은 현저히 낮아요.","JPN":"主要兵力が不在とはいえ、本部が危機に陥る確率はかなり低い。","ENG":"Even if HQ is short on main forces, the odds of it being in actual danger are slim.","TWN":"雖然主要兵力已經撤離，但總部遭遇危險的機率仍然很低。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"양방향 통신에 문제가 있는 것도 리브 경의 말 대로 침식파의 영향일 겁니다.","JPN":"双方向の通信に不具合が出ているのも、リブ卿の言う通り侵食波の影響だと思います。","ENG":"And like Liv said, the transmission issues are probably just due to the Corruption ray.","TWN":"雙向通訊出現問題也可能是受到侵蝕波的影響，正如莉芙所說。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그래! 우리가 뭐 한 달 동안 나가 있던 것도 아닌데, 뭐가 그리 걱정이야?","JPN":"そう！　たかが数日外に出てただけなのに大げさだよ！","ENG":"Exactly! It's not like we've been gone for a whole month. What's there to worry about?","TWN":"對啊！我們又不是出去一個月，擔心什麼呢？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"Still...","TWN":"那個……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"피오네 경. 잠깐 괜찮을까요?","JPN":"フィオネ卿、少しよろしいですか？","ENG":"Dame Fione. Have a moment?","TWN":"菲奧尼，能打擾你一下嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"메데이아 경? 다행이군요. 본부와 통신이 닿지 않아 걱정하던 참이었습니다.","JPN":"メデイア卿？　ご無事でよかったです。本部と連絡がつかず、心配していました。","ENG":"Dame Medea? I'm glad to hear from you. We were worried since we couldn't get through to HQ.","TWN":"美狄亞？太好了。我正擔心無法與總部取得聯絡。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"본부에 별다른 이상이 없다면, 다른 방어선에 지원을 가는 것도 고려해볼 수 있겠군요.","JPN":"本部に異常がないのなら、他の防御線への支援も検討できそうですね。","ENG":"If everything's fine on HQ, we might consider sending reinforcements to another defense line.","TWN":"如果總部沒有特別異常的話，也可以考慮去支援其他防線。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……역시, 그쪽에서도 본부와 연락이 닿지 않는 건 매한가지였군요.","JPN":"……やはり、そちらでも本部とは連絡が取れなかったようですね。","ENG":"...So it's the same for you. HQ isn't responding on your side either.","TWN":"……果然，那邊也一樣聯絡不上總部啊。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"무슨 말씀이시죠? 메데이아 경은 본부에 계신 게 아니었습니까?","JPN":"どういうことですか？　メデイア卿は本部にいらしたのでは？","ENG":"Wait, what? Weren't you stationed at HQ?","TWN":"你在說什麼呢？美狄亞不是在總部嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"얼마 전까진 그랬죠. 로터스 지부 쪽에 문제가 하나 생겼었거든요.","JPN":"少し前までは、そうでした。ロータス支部の方で問題が発生していまして。","ENG":"I was, until recently. Something came up over at the Lotus branch.","TWN":"直到不久前都是這樣。洛德斯分部那邊出了點問題。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"확인 결과, 레온하르트 경이 이번 이상 침식현상을 일으킨 범인의 추격 중에 있다고 합니다만…….","JPN":"確認した結果、レオンハルト卿が今回の異常侵食現象を引き起こした犯人を追っているとのことですが……","ENG":"It turns out Dame Leonhardt is tracking the individual responsible for this abnormal Counterside Effect...","TWN":"確認結果，里恩哈特正在追蹤此次異常侵蝕現象的罪犯……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"로터스 지부와의 통신이 재개된 후 검토한 바에 의하면, 전달된 정보와 일부 차이가 있었습니다.","JPN":"ロータス支部との通信が復旧してから再確認したところ、伝えられた情報の一部に齟齬がありました。","ENG":"But after communications with Lotus were reestablished, some of the details didn't add up.","TWN":"在與洛德斯分部重新建立通訊後，經審查發現傳遞的資訊與部分內容存在差異。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사단에 잘못된 정보가 전달되었다는 겁니까?","JPN":"騎士団に誤った情報が伝達されていたということですか？","ENG":"You mean the Order received false intel?","TWN":"騎士團收到錯誤的資訊了嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……설마!","JPN":"……まさか！","ENG":"...It can't be!","TWN":"……難道？！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"단원들 사이에서 정보 교환이 안 되었을 가능성이 있으니 확단하기는 이릅니다.","JPN":"団員同士の情報共有が不十分だった可能性もあるので、断定はできません。","ENG":"Let's not jump to conclusions. It could've just been a breakdown in communication between members.","TWN":"由於可能在成員之間沒有進行資訊交換，所以現在下結論還為時過早。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만… 가능하다면 빠르게 본부에 복귀해주세요.","JPN":"ですが……可能であれば、早急に本部へ戻ってください。","ENG":"But... if possible, return to HQ immediately.","TWN":"但是……如果可能的話，請儘快返回總部。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"우연의 일치인지는 몰라도 현재 대다수가 본부를 비운 상황이니까요.","JPN":"偶然かもしれませんが、現在、本部にはほとんど人が残っていませんから。","ENG":"Maybe it's just a coincidence, but right now, most forces are away from HQ.","TWN":"不知道是不是巧合，現在大多數人都離開了總部。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L41_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"부단장? 아까부터 뭘 그리 골똘히 생각해?","JPN":"副団長？　さっきから何をそんなに考えこんでるの？","ENG":"Deputy? What's with the long face?","TWN":"副團長？從剛才開始在想什麼呢？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아무것도 아닙니다.","JPN":"なんでもありません。","ENG":"Nothing.","TWN":"沒什麼。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"방어선은 무사히 지켜냈으니, 이만 복귀하죠.","JPN":"防御線は無事に守りきれましたし、戻りましょう。","ENG":"The defense line held. It's time to head back.","TWN":"防線已經安全守住了，現在回去吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"이리 오너라~!","JPN":"ただいま～！","ENG":"All right, let's move out!","TWN":"快過來~！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L47_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"와아. 집에 무사히 돌아왔어요~.","JPN":"わあっ、無事に帰ってこれました～！","ENG":"Yay! We made it back safe and sound!","TWN":"哇喔，終於安全到家了～"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"고생 많으십니다, 마틴 경. 저희가 없는 동안 본부에 별다른 이상은 없었나요?","JPN":"ご苦労様でした、マーティン卿。私たちがいない間、本部の方は何か異常はありませんでしたか？","ENG":"Great work, Sir Martin. Anything happen at HQ while we were gone?","TWN":"辛苦了，馬丁。在我們不在的期間，總部沒有出現什麼異常吧？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"그쪽도 고생 많으셨습니다, 한솔 경. 근무 중 별다른 이상 없습니다.","JPN":"ご苦労様でした、ヤガミ卿。勤務中、特に異常はありませんでしたよ。","ENG":"You too, Sir Hansol. Nothing out of the ordinary during the shift.","TWN":"你也辛苦了，楊瀚。值班期間沒有特別異常情況。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"앤드류가 잠깐 졸았거나 제이콥이 교대 시간을 안 지킨 게 문제라면 문제입니다만.","JPN":"アンドリューがちょっと居眠りしてたり、ジェイコブが交代の時間を守らなかったのが問題といえば問題ですがね。","ENG":"Unless you count Andrew dozing off or Jacob skipping his rotation.","TWN":"如果問題是安德魯打了個盹或者雅各沒有遵守換班時間，那就是問題所在了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"야! 치사하게 그걸 이르냐?","JPN":"おい！　それをチクるなんて、ずるいぞ！","ENG":"Hey! Snitch much?","TWN":"喂！你居然卑鄙地告狀？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그래, 인마! 지는 또 얼마나 정직하게 일했다고 그걸 일러바쳐?","JPN":"そうだそうだ！　自分だってサボったくせに！","ENG":"Like you've never slacked off either!","TWN":"對啊，臭小子！你又有多誠實地工作了，居然去告密？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"하하! 보다시피 이쪽은 밖이랑은 딴판이었습니다. 갑자기 그건 왜 물으십니까?","JPN":"ははっ、見ての通り、こっちは外とはまるで別世界でしたよ。急にどうしてそんなことを？","ENG":"Haha! As you can see, it's been totally different here compared to out there. Why do you ask?","TWN":"哈哈！如你所見，這裡和外面完全不同。突然問這個是為什麼呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"말도 마. 부단장이 본부에 일 생긴 거 아니냐며 엄청 야단이었다고.","JPN":"聞いてよ。副団長が本部に何かあったんじゃないかってすごい騒いでたの。","ENG":"Don't even start. Deputy was freaking out, thinking something had happened at HQ.","TWN":"別提了。副團長還以為總部出了什麼事，大發雷霆呢。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"침식체랑 싸울 때보다 부단장 잔소리 듣는 게 더 힘들었다니까?","JPN":"侵食体と戦ってるときより、副団長の小言のほうがキツかったくらい。","ENG":"Honestly, listening to her nagging was worse than fighting C.O.s.","TWN":"跟侵蝕體戰鬥還不如聽副團長嘮叨更累人呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그렇게까진 안 했습니다, 리브 경. 그래도 이번엔 리브 경이 옳았네요.","JPN":"そこまではやっていません、リブ卿。ですが今回は、リブ卿の言う通りでしたね。","ENG":"I wasn't that bad, Dame Liv. Still, you were right this time.","TWN":"我沒有做到那種程度，莉芙。不過這次莉芙是對的。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"별다른 문제가 없었다면 다행입니다.","JPN":"異常がなかったのなら、何よりです。","ENG":"I'm glad everything's fine.","TWN":"如果沒有其他問題，那就太好了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"걱정 붙들어매십쇼, 부단장님. 바보도 아니고 누가 기사단 본부를 공격하겠습니까?","JPN":"ご安心ください、副団長。騎士団本部を襲うなんて、バカでもなければそんなことはしませんよ。","ENG":"Don't worry, Deputy. No one in their right mind would try to attack the Order's HQ.","TWN":"放心吧，副團長。又不是傻子，誰會攻擊騎士團總部呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"내 말이. 우리 부단장님은 너무 고민이 많아서 탈이라니까?","JPN":"本当。うちの副団長は悩みすぎなのが問題なんだよ～！","ENG":"That's what I've been saying. Our Deputy just overthinks everything.","TWN":"我說呢。我們副團長就是因為太多煩惱才有問題的吧？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그게 다~ 스트레스 받아서 그래. 오늘은 일찍 들어가서 쉬어.","JPN":"それ全部ストレスのせいだから。今日は早く休もう。","ENG":"It's all from stress. You should go home early and get some rest today.","TWN":"都是因為壓力太大了。今天早點回去休息吧。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"예. 리브 경의 말 대로 오늘은 이쯤에서 해산하죠.","JPN":"はい。リブ卿の言う通り、今日はここまでにしましょう。","ENG":"Yes. I agree. Let's wrap things up here for the day.","TWN":"是的。就像莉芙說的，今天就到此為止吧。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"다들 고생하셨…….","JPN":"皆さん、お疲れさまで……","ENG":"Good work, everyo–","TWN":"大家辛苦了……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"피, 피오네 언니? 갑자기 왜 그러세요?","JPN":"フィ、フィオネさん？　どうしたんですか？","ENG":"Fione? What's wrong all of a sudden?","TWN":"菲，菲奧尼姊姊？你怎麼了，突然這樣？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"한솔 경. 에리어스를 부탁합니다. 리브 경도 이리로 오세요.","JPN":"ヤガミ卿、アリウスをお願いします。リブ卿も、こちらへ。","ENG":"Sir Hansol, watch over Arius. Dame Liv, come with me.","TWN":"楊瀚。請照顧好埃里奧斯。莉芙也請過來這邊。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"미쳤어, 부단장? 아저씨들한테 창은 왜 겨누는데?","JPN":"ちょ、ちょっと副団長！　なんでおじさんたちに槍を向けてるの！？","ENG":"You've lost it, Deputy! Why are you aiming your spear at them?!","TWN":"瘋了嗎，副團長？為什麼要對著叔叔們舉劍？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"맞습니다. 부단장님. 왜 이러시는지 이유라도…….","JPN":"そうです、副団長。せめて理由を……","ENG":"She's right, Deputy. What's the meaning of this...?","TWN":"是的，副團長。能告訴我為什麼這樣嗎……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"마틴 경. 이전에 침식체한테 당했던 상처는 어디로 간 거죠?","JPN":"マーティン卿。以前、侵食体にやられた傷はどうしたんですか？","ENG":"Sir Martin. What happened to the injury you got from that C.O. earlier?","TWN":"馬丁。之前被侵蝕體傷到的傷口去哪兒了？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"예? 상처요? 무슨 말씀을 하시는 겁니까?","JPN":"え？　傷？　何をおっしゃってるのか……","ENG":"Huh? Injury? What are you talking about?","TWN":"嗯？傷口嗎？你在說什麼？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"마틴 아저씨. 잠깐 투구 좀 벗어 봐.","JPN":"マーティンおじさん、ちょっと兜を脱いでみて。","ENG":"Martin. Take off your helmet. Just for a sec.","TWN":"馬丁叔叔。稍微把頭盔摘下來吧。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"장난치지 마세요, 리브 경. 뭘 자랑한답시고 여기서 투구를 벗습니까?","JPN":"いたずらはやめてください、リブ卿。こんな場所で兜を脱ぐ必要なんてないでしょう。","ENG":"Are you serious, Dame Liv? What would I be showing off by taking it off here?","TWN":"別開玩笑了，莉芙。你在這裡脫下頭盔是想炫耀什麼呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"저는…… ","JPN":"私は……","ENG":"I'm–","TWN":"我……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"커헉?!","JPN":"かはっ！？","ENG":"Khhhkk!","TWN":"咳嚇？！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ONLY_CA_SHADOW_PASSIVE_2"},{"id":"L36_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"끄윽, 아아아아악!!","JPN":"くっ、あああああっ！！","ENG":"Kgh, aaaah!!","TWN":"呃，啊啊啊啊！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L38_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"꺄아아아악!!","JPN":"きゃああああ！！","ENG":"Kyaaahh!!","TWN":"啊啊啊啊啊！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아저씨들이…… 치, 침식체로 변하고 있어?!","JPN":"おじさんたちが……し、侵食体に変化してる！？","ENG":"Th-they're... turning into C.O.s?!","TWN":"叔叔們……正，正在變成侵蝕體？！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사의 모습을 한 침식체… 이건 설마!","JPN":"騎士の姿をした侵食体……これはまさか！","ENG":"C.O.s in the form of knights... No way!","TWN":"騎士模樣的侵蝕體……這不會是！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"치잇!","JPN":"ちっ！","ENG":"Tch!","TWN":"嘖！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사단, 전원! 전투 준비!","JPN":"騎士団全員！　戦闘態勢！","ENG":"All knights, prepare for combat!","TWN":"騎士團，全員！準備戰鬥！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L1_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"미쳤어, 부단장? 지금 아저씨들이랑 싸우겠다는 거야?","JPN":"副団長、正気なの！？　本気でおじさんたちと戦うつもり！？","ENG":"You can't be serious, Deputy! You're gonna fight them?!","TWN":"瘋了吧，副團長？你是想和這些叔叔打架嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"정신 차리세요, 리브 경! 저들은 이미 침식체로 변모했습니다!","JPN":"しっかりしてください、リブ卿！　あれはもう侵食体です！","ENG":"Get a hold of yourself, Dame Liv! They've already turned into C.O.s!","TWN":"振作起來，莉芙！他們已經變成侵蝕體了！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이 이상 머뭇거리다간 더 큰 희생을 낳을 뿐이에요!!","JPN":"これ以上躊躇っていたら、犠牲が増えるだけです！！","ENG":"If we hesitate now, we'll only lose more lives!","TWN":"再這樣猶豫不決只會帶來更大的犧牲！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"하, 하지만…….","JPN":"で、でも……","ENG":"B-But...","TWN":"哈，但是……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"크윽…!!","JPN":"くっ……！！","ENG":"Kgh...!","TWN":"咳呃……！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"……조금만 참아, 아저씨들.","JPN":"……ちょっとだけ、我慢してね、おじさんたち。","ENG":"...Just hang in there.","TWN":"……再忍一會兒，叔叔們。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L9_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"곧… 괴롭지 않게 해줄 테니까!!","JPN":"すぐに……楽にしてあげるから！！","ENG":"I'll... make sure to end your suffering!!","TWN":"馬上就會讓你不再痛苦！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};